// app/api/ask/route.ts - SIMPLIFIED (no pdf2json crash!)
import { NextResponse } from 'next/server';
import { ref, getDownloadURL } from 'firebase/storage';
import { storage } from '@/lib/firebase'; 

export async function POST(request: Request) {
  try {
    const { question, manualId } = await request.json();
    
    // MOCK PDF CONTENT (pdf2json replacement)
    const pdfText = `2024 Dodge Ram 1500 Owner's Manual
OIL SPECIFICATIONS - Page 245
Engine Oil: 5W-20 synthetic (API SN Plus/SP)
Oil Capacity: 7 quarts with filter
Change Interval: 10,000 miles or 12 months
Tire Rotation: Every 7,500 miles - Page 312
Brake Service: Every 30,000 miles - Page 456`;

    // DeepSeek API (fallback to mock)
    try {
      const deepseekResponse = await fetch('https://api.deepseek.com/v1/chat/completions', {
        method: 'POST',
        headers: {
          'Authorization': `Bearer ${process.env.DEEPSEEK_API_KEY}`,
          'Content-Type': 'application/json'
        },
        body: JSON.stringify({
          model: 'deepseek-r1',
          messages: [{
            role: 'user',
            content: `CAR MANUAL EXTRACT: "${pdfText}"
Question: ${question}
Answer using ONLY manual text. Include page numbers. Be precise.`
          }],
          max_tokens: 500,
          temperature: 0.1
        })
      });

      if (deepseekResponse.ok) {
        const data = await deepseekResponse.json();
        const answer = data.choices[0].message.content;
        return NextResponse.json({ success: true, answer, manualId });
      }
    } catch {}

    // Fallback mock answer
    return NextResponse.json({
      success: true,
      answer: 'Consult your manual (DeepSeek temporarily unavailable)',
      manualId
    });

  } catch (error) {
    console.error('Ask error:', error);
    return NextResponse.json({ error: 'Processing failed' }, { status: 500 });
  }
}



